import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.DeBUZsJm.js";const p=JSON.parse('{"title":"Introduction","description":"Desktop-native plugins for Astrogram with host-rendered settings, recovery and real client hooks.","frontmatter":{"title":"Introduction","description":"Desktop-native plugins for Astrogram with host-rendered settings, recovery and real client hooks."},"headers":[],"relativePath":"Introduction.md","filePath":"Introduction.md","lastUpdated":1775513914000}'),r={name:"Introduction.md"};function l(n,e,s,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Build native plugins for Astrogram Desktop with C++20, Qt and a host runtime that already knows how to render settings, recover from bad loads and expose real desktop windows or session state.</p><h2 id="what-astrogram-plugins-are" tabindex="-1">What Astrogram plugins are <a class="header-anchor" href="#what-astrogram-plugins-are" aria-label="Permalink to &quot;What Astrogram plugins are&quot;">​</a></h2><p>Astrogram plugins are compiled <code>.tgd</code> modules loaded directly by the desktop client.</p><ul><li>they use the same native toolchain as the client</li><li>they talk to a stable plugin API instead of patching random memory</li><li>they can register settings, commands, interceptors, metadata previews and window handlers</li></ul><h2 id="what-the-host-already-gives-you" tabindex="-1">What the host already gives you <a class="header-anchor" href="#what-the-host-already-gives-you" aria-label="Permalink to &quot;What the host already gives you&quot;">​</a></h2><p>The runtime is designed so plugins do not have to reinvent the same plumbing every time.</p><h3 id="host-rendered-settings" tabindex="-1">Host-rendered settings <a class="header-anchor" href="#host-rendered-settings" aria-label="Permalink to &quot;Host-rendered settings&quot;">​</a></h3><p>Settings pages are rendered by Astrogram itself, so a plugin can expose sliders, toggles, text fields and actions without building fragile standalone dialogs.</p><h3 id="real-desktop-hooks" tabindex="-1">Real desktop hooks <a class="header-anchor" href="#real-desktop-hooks" aria-label="Permalink to &quot;Real desktop hooks&quot;">​</a></h3><p>Plugins can work with actual Astrogram windows, active sessions, commands and interceptors instead of only static metadata.</p><h3 id="recovery-aware-loading" tabindex="-1">Recovery-aware loading <a class="header-anchor" href="#recovery-aware-loading" aria-label="Permalink to &quot;Recovery-aware loading&quot;">​</a></h3><p>When a plugin breaks load or UI flow, Astrogram can attribute the crash, enter safe mode, disable the bad plugin and let the user recover instead of looping forever.</p><h2 id="build-model" tabindex="-1">Build model <a class="header-anchor" href="#build-model" aria-label="Permalink to &quot;Build model&quot;">​</a></h2><p>To build a working plugin, it must match the client runtime:</p><ul><li>same platform</li><li>same architecture</li><li>same compiler ABI</li><li>same Qt major and minor version</li><li>same Astrogram plugin API version</li></ul><p>If one of these does not match, the loader will reject the binary instead of pretending it is safe.</p><h2 id="typical-workflow" tabindex="-1">Typical workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical workflow&quot;">​</a></h2><ol><li>Start from <code>Telegram/Plugins/Examples</code>.</li><li>Include <code>Telegram/SourceFiles/plugins/plugins_api.h</code>.</li><li>Export preview metadata with <code>TGD_PLUGIN_PREVIEW(...)</code>.</li><li>Build the plugin and rename the output to <code>.tgd</code>.</li><li>Drop it into <code>tdata/plugins</code>.</li><li>Open <code>Settings &gt; Astrogram &gt; Plugins</code>.</li></ol><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="/setup">Setup</a> for folders, ABI expectations and install basics</li><li><a href="/first-plugin">First Plugin</a> for the minimal plugin skeleton</li><li><a href="/plugin-settings">Plugin Settings</a> for host-side controls</li><li><a href="/runtime-api">Runtime API</a> for windows, sessions and helper calls</li></ul>',21)])])}const g=t(r,[["render",l]]);export{p as __pageData,g as default};
